package store

import (
	"context"
	"errors"
	"fmt"
	"os"
	"strings"
	"sync"
	"time"

	"k8s.io/klog/v2"
)

var (
	// ErrNotFound is returned when a session key is not found
	ErrNotFound = errors.New("store: not found")
)

// Store defines the interface for session storage
type Store interface {
	// Ping verifies connectivity to the backend
	Ping(ctx context.Context) error

	// GetSandboxBySessionID retrieves sandbox metadata by session ID
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)

	// StoreSandbox persists sandbox metadata
	StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error

	// UpdateSandbox updates existing sandbox metadata
	UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error

	// DeleteSandboxBySessionID removes sandbox by session ID
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error

	// ListExpiredSandboxes returns session IDs with expiry before given time
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error)

	// ListInactiveSandboxes returns session IDs with last activity before given time
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error)

	// UpdateSessionLastActivity updates the last activity timestamp
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error

	// Close closes the store connection
	Close() error
}

var (
	storage     Store
	storageOnce sync.Once
)

// Storage returns the singleton store instance
func Storage() Store {
	storageOnce.Do(func() {
		var err error
		storage, err = initStore()
		if err != nil {
			klog.Fatalf("Failed to initialize storage: %v", err)
		}
	})
	return storage
}

func initStore() (Store, error) {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = "redis"
	}

	switch storeType {
	case "redis":
		return NewRedisStore()
	default:
		return nil, fmt.Errorf("unsupported STORE_TYPE: %s, must be 'redis'", storeType)
	}
}

