// ValkeyStore implements Store interface using Valkey
type ValkeyStore struct {
	client valkey.Client
}

// NewValkeyStore creates a new Valkey store
func NewValkeyStore() (*ValkeyStore, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, errors.New("VALKEY_ADDR environment variable is required")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if strings.ToLower(passwordRequired) != "false" && password == "" {
		return nil, errors.New("VALKEY_PASSWORD environment variable is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	// Parse addresses
	addresses := strings.Split(addr, ",")
	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:       addresses,
		Password:          password,
		DisableCache:      getBoolEnv("VALKEY_DISABLE_CACHE", false),
		ForceSingleClient: getBoolEnv("VALKEY_FORCE_SINGLE", false),
	})
	if err != nil {
		return nil, fmt.Errorf("failed to create Valkey client: %w", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Do(ctx, client.B().Ping()).Error(); err != nil {
		return nil, fmt.Errorf("failed to connect to Valkey: %w", err)
	}

	klog.Info("Successfully connected to Valkey")
	return &ValkeyStore{client: client}, nil
}

// Ping verifies connectivity
func (v *ValkeyStore) Ping(ctx context.Context) error {
	result, err := v.client.Do(ctx, v.client.B().Ping()).ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

