}

// Ping verifies connectivity
func (v *ValkeyStore) Ping(ctx context.Context) error {
	result, err := v.client.Do(ctx, v.client.B().Ping()).ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

// GetSandboxBySessionID retrieves sandbox metadata
func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	data, err := v.client.Do(ctx, v.client.B().Get().Key(key)).ToString()
	if valkey.IsValkeyNil(err) {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox data: %w", err)
	}

	return &sandbox, nil
}

// StoreSandbox persists sandbox metadata
func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt cannot be zero")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox data: %w", err)
	}

	key := sessionKeyPrefix + sandbox.SessionID

	// Use multi/exec for atomic operations
	m := v.client.Multi()
	defer m.Close()

	cmd := m.B().Set().Key(key).Value(string(data)).Build()
	m.Exec(ctx, cmd)

	// Add to expiry index
	expiryCmd := m.B().Zadd().Key(expiryZSETKey).
		ScoreMember().
		Score(float64(sandbox.ExpiresAt.Unix())).
		Member(sandbox.SessionID).Build()
	m.Exec(ctx, expiryCmd)

	// Add to activity index
	activityTime := time.Now()
	if !sandbox.LastActivity.IsZero() {
		activityTime = sandbox.LastActivity
	}
	activityCmd := m.B().Zadd().Key(activityZSETKey).
		ScoreMember().
		Score(float64(activityTime.Unix())).
		Member(sandbox.SessionID).Build()
	_, err = m.Exec(ctx, activityCmd)
	if err != nil {
		return fmt.Errorf("pipeline execution failed: %w", err)
	}

	return nil
}

// UpdateSandbox updates existing sandbox metadata
func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox data: %w", err)
	}

	key := sessionKeyPrefix + sandbox.SessionID
	result, err := v.client.Do(ctx, v.client.B().Set().
		Key(key).
		Value(string(data)).
		XX().Build()).ToString()
	if err != nil {
		return err
	}
	if result != "OK" {
		return errors.New("key not exists")
	}

	return nil
}

// DeleteSandboxBySessionID removes sandbox by session ID
func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	m := v.client.Multi()
	defer m.Close()

	delCmd := m.B().Del().Key(key).Build()
	zRemExpiryCmd := m.B().Zrem().Key(expiryZSETKey).Member(sessionID).Build()
	zRemActivityCmd := m.B().Zrem().Key(activityZSETKey).Member(sessionID).Build()

	_, err := m.Exec(ctx, delCmd, zRemExpiryCmd, zRemActivityCmd)
	return err
}

// ListExpiredSandboxes returns session IDs expired before given time
func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result, err := v.client.Do(ctx, v.client.B().Zrangebyscore().
		Key(expiryZSETKey).
		Min("-inf").
		Max(fmt.Sprintf("%d", before.Unix())).
		Offset(0).
		Count(int64(limit)).Build()).ToArray()
	if err != nil {
		return nil, err
	}

	ids := make([]string, 0, len(result))
	for _, item := range result {
		if str, ok := item.(string); ok {
			ids = append(ids, str)
		}
	}
	return ids, nil
}

// ListInactiveSandboxes returns session IDs inactive before given time
func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result, err := v.client.Do(ctx, v.client.B().Zrangebyscore().
		Key(activityZSETKey).
